#include <Rcpp.h>
using namespace Rcpp;
//[[Rcpp::export]]

NumericVector  dgammaC(NumericVector x, double alpha, double beta, int
give_log)
{
        int T = x.size();
        NumericVector f(T);
        for(int t=0;t<T; t++)
                {
                f(t) = R::dgamma(x(t), alpha, beta, give_log);
                }
        return f;
}


